/**
 * AI 服务 - 主进程 IPC 处理器
 * 处理渲染进程发来的 AI 相关 IPC 调用
 */

import { IpcMain, BrowserWindow, safeStorage } from 'electron'
import axios, { AxiosError } from 'axios'
import fs from 'node:fs'
import path from 'node:path'
import os from 'node:os'
import { app } from 'electron'

// ─── 配置路径 ────────────────────────────────────────────────────────────────

function getSettingsPath(): string {
  return path.join(app.getPath('userData'), 'ai-settings.json')
}

// 获取 API Key（自动解密 encrypted: 前缀的存储值）
async function getApiKey(model: string): Promise<string | null> {
  const settings = loadSettings()
  const fallbackKey = model.startsWith('doubao')
    ? process.env.DOUBAO_API_KEY
    : process.env.DEEPSEEK_API_KEY
  const raw = settings[`${model}ApiKey`] || fallbackKey
  if (!raw) return null
  if (raw.startsWith('encrypted:')) {
    try {
      const base64 = raw.slice('encrypted:'.length)
      const encrypted = Buffer.from(base64, 'base64')
      if (!safeStorage.isEncryptionAvailable()) return raw
      const decrypted = safeStorage.decryptString(encrypted)
      return decrypted
    } catch {
      return raw  // 解密失败时降级（不阻塞）
    }
  }
  return raw
}

// ─── 配置读写 ────────────────────────────────────────────────────────────────

interface AiSettings {
  deepseekApiKey?: string
  doubaoApiKey?: string
  [key: string]: string | undefined
}

function loadSettings(): AiSettings {
  const p = getSettingsPath()
  if (fs.existsSync(p)) {
    try {
      return JSON.parse(fs.readFileSync(p, 'utf-8'))
    } catch {
      return {}
    }
  }
  return {}
}

